/// C: `static void prepcallclosemth(lua_State *L, StkId level, int status, int yy)`
fn prep_call_close_mth(
    state: &mut LuaState,
    level: StackIdx,
    status: i32,
    yy: bool,
) -> Result<(), LuaError> {
    // C: TValue *uv = s2v(level);  /* value being closed */
    //    TValue *errobj;
