        state.push_copy(1)?;
        state.concat(2)?;
        let after = state.peek_bytes(-1).map(|v| String::from_utf8_lossy(&v).into_owned());
        eprintln!("[DBG error_fn] after concat top={:?}", after);
    }
    let popped = state.pop();
    eprintln!("[DBG error_fn] popped={:?}", popped);
    // C: return lua_error(L);
    Err(LuaError::from_value(popped))
}

