// C: LUA_HOOKCALL, LUA_HOOKRET, LUA_HOOKTAILCALL event codes
const LUA_HOOKCALL: i32 = 0;
const LUA_HOOKRET: i32 = 1;
const LUA_HOOKTAILCALL: i32 = 4;

