            eprintln!("[DBG state_stub push_where] currentline={} short_src={:?}", ar.currentline, std::str::from_utf8(&ar.short_src).unwrap_or("<bin>"));
            if ar.currentline > 0 {
                let zero = ar
                    .short_src
                    .iter()
                    .position(|&b| b == 0)
                    .unwrap_or(ar.short_src.len());
                let mut buf: Vec<u8> = ar.short_src[..zero].to_vec();
